func doUserService_UpdateUser(getCfg func() *config.Config, getOutput func() string, cmd *cobra.Command, req *userpb.UpdateUserRequest) error {
	dryRun, _ := cmd.Flags().GetBool("dry-run")
	if dryRun {
		reqJSON, err := protojson.MarshalOptions{Indent: "  "}.Marshal(req)
		if err != nil {
			return fmt.Errorf("marshalling request: %w", err)
		}
		envelope := map[string]json.RawMessage{
			"method":  json.RawMessage(fmt.Sprintf("%q", "zitadel.user.v2.UserService/UpdateUser")),
			"request": json.RawMessage(reqJSON),
		}
		out, _ := json.MarshalIndent(envelope, "", "  ")
		fmt.Println(string(out))
		return nil
	}

	cfg := getCfg()
	actx, _, err := config.ActiveCtx(cfg)
	if err != nil {
		return err
	}
	tokenSource, err := auth.TokenSource(cmd.Context(), actx)
	if err != nil {
		return err
	}
	httpClient := client.New(tokenSource)
	baseURL := client.InstanceURL(actx.Instance)
	svcClient := userconnect.NewUserServiceClient(httpClient, baseURL)

	resp, err := svcClient.UpdateUser(cmd.Context(), connect.NewRequest(req))
	if err != nil {
		return FormatConnectError(err)
	}

	if getOutput() == "json" {
		return output.JSON(resp.Msg)
	}

	header := []string{"CHANGE DATE", "EMAIL CODE", "PHONE CODE"}
	rows := [][]string{
		{
			func() string {
				if t := resp.Msg.GetChangeDate(); t != nil {
					return t.AsTime().Format("2006-01-02T15:04:05Z")
				}
				return ""
			}(),
			fmt.Sprint(resp.Msg.GetEmailCode()),
			fmt.Sprint(resp.Msg.GetPhoneCode()),
		},
	}
	output.Table(header, rows)
	return nil
}

